// // This comment suggests the circuit operates asynchronously, but in reality, it is synchronous with a one-cycle delay.
module top_module(
    input wire clk,       // Added clk input
    input wire data,
    output wire to_pad
);reg delayed_data;

always @(posedge clk) begin
    delayed_data <= data;
end

assign to_pad = delayed_data;

endmodule
